  }
});

A.$("btn-export-priv").addEventListener("click", async () => {
  try {
    const ownerId = A.$("key-user-select").value;
    if (!ownerId) {
      throw new Error("Выбери пользователя для экспорта private key.");
    }
    const key = await A.api(`/api/keys/${ownerId}/private`);
