    });
    A.setOut("keys-out", { ownerId, imported: true });
    explain("import keys: ключевая пара записана в локальный KeyVault-адаптер.");
  } catch (e) {
    A.setOut("keys-out", e.message);
  }
});

A.$("btn-audit").addEventListener("click", async () => {
