const STORAGE_KEY = "securemsg.users.v1";

function $(id) {
  return document.getElementById(id);
}

function setOut(id, data) {
  const el = $(id);
  if (!el) {
    return;
  }
  const text = typeof data === "string" ? data : JSON.stringify(data, null, 2);
  el.textContent = text;
}

function setExplain(id, text) {
  const el = $(id);
  if (el) {
    el.textContent = text;
  }
}

async function api(path, method = "GET", body, headers = {}) {
  const options = { method, headers: { ...headers } };
  if (body !== undefined) {
    if (body instanceof ArrayBuffer || body instanceof Blob) {
      options.body = body;
    } else {
      options.headers["Content-Type"] = "application/json";
      options.body = JSON.stringify(body);
    }
  }

  const response = await fetch(path, options);
  const text = await response.text();
  const payload = text ? tryParseJson(text) : null;
  if (!response.ok) {
    const errorText = typeof payload === "string" ? payload : JSON.stringify(payload, null, 2);
    throw new Error(`HTTP ${response.status}: ${errorText}`);
  }
  return payload;
}

function tryParseJson(text) {
  try {
    return JSON.parse(text);
  } catch (_) {
    return text;
  }
}

function loadUsers() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return [];
    }
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch (_) {
    return [];
  }
}

function saveUsers(users) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(users));
}

function upsertUser(user) {
  const users = loadUsers();
  const payload = {
    login: user.login,
    id: user.id,
    token: user.hardwareTokenSecret || "",
    role: user.role || "USER",
  };

  const idx = users.findIndex((u) => u.login === user.login);
  if (idx >= 0) {
    users[idx] = { ...users[idx], ...payload };
  } else {
    users.push(payload);
  }
  saveUsers(users);
  return users;
}

function getUserByLogin(login) {
  return loadUsers().find((u) => u.login === login.trim()) || null;
}

function getUserById(id) {
  return loadUsers().find((u) => u.id === id) || null;
}

function getIdByLogin(login) {
  const user = getUserByLogin(login);
  return user ? user.id : null;
}

function fillUserSelect(selectId) {
  const el = $(selectId);
  if (!el) {
    return;
  }
  const users = loadUsers();
  el.innerHTML = users
    .map((u) => `<option value="${u.id}">${u.login} (${u.id.slice(0, 8)})</option>`)
    .join("");
}

function fillManyUserSelects(selectIds) {
  selectIds.forEach((id) => fillUserSelect(id));
}

function compactMessage(message) {
  if (!message) {
    return message;
  }
  return {
    id: message.id,
    senderId: message.senderId,
    recipientId: message.recipientId,
    groupId: message.groupId,
    status: message.status,
    ratchetStep: message.ratchetStep,
    createdAt: message.createdAt,
    payloadSize: message.encryptedPayload ? message.encryptedPayload.length : 0,
    signatureSize: message.signature ? message.signature.length : 0,
  };
}

function compactMessages(messages) {
  if (!Array.isArray(messages)) {
    return messages;
  }
  return messages.map(compactMessage);
}

function markStep(stepId, state) {
  const el = $(stepId);
  if (!el) {
    return;
  }
  el.classList.remove("step-ok", "step-run", "step-wait");
  el.classList.add(state);
}

window.DemoUI = {
  $, setOut, setExplain, api,
  loadUsers, saveUsers, upsertUser, getUserByLogin, getUserById, getIdByLogin,
  fillUserSelect, fillManyUserSelects,
  compactMessage, compactMessages, markStep,
};

const F = window.DemoUI;

function explain(text) {
  F.setExplain("files-explain", text);
}

function setOut(data) {
  F.setOut("files-out", data);
}

function fillSelects() {
  F.fillManyUserSelects(["file-sender-select", "file-recipient-select"]);
}

function resetSteps() {
  ["f-step-init", "f-step-chunk", "f-step-final", "f-step-verify", "f-step-delivered"]
    .forEach((id) => F.markStep(id, "step-wait"));
}

F.$("btn-upload-file").addEventListener("click", async () => {
  try {
    fillSelects();
    resetSteps();

    const senderId = F.$("file-sender-select").value;
    const recipientId = F.$("file-recipient-select").value;
    const file = F.$("file-input").files[0];
    if (!senderId || !recipientId || !file) {
      throw new Error("Выбери отправителя, получателя и файл перед запуском pipeline.");
    }

    F.markStep("f-step-init", "step-run");
    const init = await F.api("/api/files/init", "POST", {
      senderId,
      recipientId,
      fileName: file.name,
      totalSize: file.size,
    });
    F.markStep("f-step-init", "step-ok");

    F.markStep("f-step-chunk", "step-run");
    const chunk = await F.api(
      `/api/files/${init.id}/chunk?offset=0`,
      "POST",
      await file.arrayBuffer(),
      { "Content-Type": "application/octet-stream" }
    );
    F.markStep("f-step-chunk", "step-ok");

    F.markStep("f-step-final", "step-run");
    const finalized = await F.api(`/api/files/${init.id}/finalize`, "POST");
    F.markStep("f-step-final", "step-ok");

    F.markStep("f-step-verify", "step-run");
    const verified = await F.api(`/api/files/${init.id}/verify?checksum=${finalized.checksumSha256}`);
    F.markStep("f-step-verify", "step-ok");

    F.markStep("f-step-delivered", "step-run");
    await F.api(`/api/files/${init.id}/delivered`, "POST");
    F.markStep("f-step-delivered", "step-ok");

    explain("pipeline: файл загружен, зашифрован, проверен по checksum и отмечен как delivered.");
    setOut({ init, chunk, finalized, verified });
  } catch (e) {
    setOut(e.message);
  }
});

fillSelects();
setOut("Сценарий: подготовка -> запуск pipeline -> наблюдение шагов INIT..DELIVERED.");

const G = window.DemoUI;

function explain(text) {
  G.setExplain("groups-explain", text);
}

function setOut(data) {
  G.setOut("groups-out", data);
}

function fillSelects() {
  G.fillManyUserSelects(["group-owner-select", "group-sender-select"]);
}

G.$("btn-create-group").addEventListener("click", async () => {
  try {
    fillSelects();
    G.markStep("g-step-create", "step-run");

    const ownerId = G.$("group-owner-select").value;
    const name = G.$("group-name").value.trim();
    if (!ownerId || !name) {
      throw new Error("Для создания группы выбери владельца и укажи название.");
    }

    const requestedLogins = G.$("group-members").value
      .split(",")
      .map((x) => x.trim())
      .filter(Boolean);

    const memberIds = requestedLogins
      .map((login) => G.getIdByLogin(login))
      .filter((id) => id !== null);

    if (!memberIds.includes(ownerId)) {
      memberIds.push(ownerId);
    }

    const group = await G.api("/api/messages/group", "POST", {
      ownerId,
      name,
      members: memberIds,
    });

    G.$("group-id").value = group.id;
    G.markStep("g-step-create", "step-ok");
    explain("group create: сервер создал чат и зафиксировал состав участников.");
    setOut({ info: "group created", group });
  } catch (e) {
    setOut(e.message);
    G.markStep("g-step-create", "step-wait");
  }
});

G.$("btn-send-group").addEventListener("click", async () => {
  try {
    G.markStep("g-step-send", "step-run");
    const groupId = G.$("group-id").value.trim();
    const senderId = G.$("group-sender-select").value;
    const text = G.$("group-text").value;
    if (!groupId || !senderId || !text) {
      throw new Error("Для отправки в группу укажи groupId, отправителя и текст.");
    }

    const messages = await G.api(`/api/messages/group/${groupId}/send`, "POST", {
      senderId,
      text,
    });
    G.markStep("g-step-send", "step-ok");
    explain("group send: одно сообщение раскладывается в персональные сообщения участникам.");
    setOut({ info: "group sent", generatedMessages: G.compactMessages(messages) });
  } catch (e) {
    setOut(e.message);
    G.markStep("g-step-send", "step-wait");
  }
});

fillSelects();
setOut("Сначала выполни сценарий A (создание), затем сценарий B (отправка в группу).");

const M = window.DemoUI;

function explain(text) {
  M.setExplain("messages-explain", text);
}

function setMsgOut(data) {
  M.setOut("messages-out", data);
}

function resetSteps() {
  ["m-step-send", "m-step-deliver", "m-step-read", "m-step-error"].forEach((id) => M.markStep(id, "step-wait"));
}

function ensureUserSelects() {
  M.fillManyUserSelects(["sender-select", "recipient-select", "history-user-select", "reader-select"]);
}

M.$("btn-send").addEventListener("click", async () => {
  try {
    ensureUserSelects();
    resetSteps();
    M.markStep("m-step-send", "step-run");

    const senderId = M.$("sender-select").value;
    const recipientId = M.$("recipient-select").value;
    const text = M.$("msg-text").value;
    if (!senderId || !recipientId || !text) {
      throw new Error("Для отправки заполни отправителя, получателя и текст.");
    }

    const message = await M.api("/api/messages/send", "POST", {
      senderId,
      recipientId,
      text,
    });

    M.$("message-id").value = message.id;
    M.markStep("m-step-send", "step-ok");
    explain("send: сообщение зашифровано, подписано и сохранено со статусом SENT/QUEUED.");
    setMsgOut({ info: "sent", message: M.compactMessage(message) });
  } catch (e) {
    setMsgOut(e.message);
    M.markStep("m-step-send", "step-wait");
  }
});

M.$("btn-deliver").addEventListener("click", async () => {
  try {
    const id = M.$("message-id").value.trim();
    if (!id) {
      throw new Error("Укажи messageId для установки статуса DELIVERED.");
    }
    M.markStep("m-step-deliver", "step-run");
    await M.api(`/api/messages/${id}/deliver`, "POST");
    M.markStep("m-step-deliver", "step-ok");
    explain("deliver: статус доставки обновлен на DELIVERED.");
    setMsgOut({ info: "delivered", messageId: id });
  } catch (e) {
    setMsgOut(e.message);
    M.markStep("m-step-deliver", "step-wait");
  }
});

M.$("btn-read").addEventListener("click", async () => {
  try {
    const id = M.$("message-id").value.trim();
    const readerId = M.$("reader-select").value;
    if (!id || !readerId) {
      throw new Error("Для READ укажи messageId и читателя.");
    }
    M.markStep("m-step-read", "step-run");
    await M.api(`/api/messages/${id}/read?readerId=${readerId}`, "POST");
    M.markStep("m-step-read", "step-ok");
    explain("read: получатель прочитал сообщение, статус READ.");
    setMsgOut({ info: "read", messageId: id, readerId });
  } catch (e) {
    setMsgOut(e.message);
    M.markStep("m-step-read", "step-wait");
  }
});

M.$("btn-error").addEventListener("click", async () => {
  try {
    const id = M.$("message-id").value.trim();
    if (!id) {
      throw new Error("Укажи messageId для установки статуса ERROR.");
    }
    M.markStep("m-step-error", "step-run");
    await M.api(`/api/messages/${id}/error`, "POST", { reason: "demo-error" });
    M.markStep("m-step-error", "step-ok");
    explain("error: сообщение помечено как ERROR для сценария отказа/инцидента.");
    setMsgOut({ info: "error", messageId: id });
  } catch (e) {
    setMsgOut(e.message);
    M.markStep("m-step-error", "step-wait");
  }
});

M.$("btn-history").addEventListener("click", async () => {
  try {
    const userId = M.$("history-user-select").value;
    if (!userId) {
      throw new Error("Выбери пользователя для просмотра истории.");
    }
    const history = await M.api(`/api/messages/history/${userId}`);
    explain("history: синхронизация хранилища сообщений для выбранного пользователя.");
    setMsgOut({ info: "history", userId, messages: M.compactMessages(history) });
  } catch (e) {
    setMsgOut(e.message);
  }
});

M.$("btn-offline").addEventListener("click", async () => {
  try {
    const userId = M.$("history-user-select").value;
    if (!userId) {
      throw new Error("Выбери пользователя для считывания офлайн-очереди.");
    }
    const offline = await M.api(`/api/messages/offline/${userId}`);
    explain("offline pull: выдача накопленной очереди сообщений для офлайн-получателя.");
    setMsgOut({ info: "offline", userId, messages: M.compactMessages(offline) });
  } catch (e) {
    setMsgOut(e.message);
  }
});

ensureUserSelects();
setMsgOut("Сценарий: отправка -> статус -> история/офлайн. Если список пуст, сначала создай пользователей.");

:root {
  color-scheme: dark;
  --bg: #0b1020;
  --panel: #131a2a;
  --panel-border: #24314f;
  --text: #e8ecf7;
  --muted: #95a2c0;
  --accent: #5ba7ff;
  --ok: #2fcd7c;
  --run: #f3c34a;
  --wait: #5f6f96;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: Arial, sans-serif;
  background: radial-gradient(circle at top, #18223d, var(--bg));
  color: var(--text);
}

header {
  padding: 20px;
  border-bottom: 1px solid var(--panel-border);
}

header h1 {
  margin: 0 0 8px;
}

header p {
  margin: 0;
  color: var(--muted);
}

main {
  max-width: 1200px;
  margin: 16px auto;
  padding: 0 16px 32px;
  display: grid;
  gap: 14px;
}

.grid-2 {
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
}

.nav-bar {
  max-width: 1200px;
  margin: 10px auto 0;
  padding: 0 16px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.nav-link {
  color: var(--text);
  text-decoration: none;
  padding: 8px 10px;
  border: 1px solid #2d3d62;
  border-radius: 8px;
  background: #0f1526;
}

.nav-link.active {
  border-color: var(--accent);
}

.card {
  background: color-mix(in srgb, var(--panel) 95%, black);
  border: 1px solid var(--panel-border);
  border-radius: 10px;
  padding: 12px;
}

.scenario {
  border: 1px dashed #334a7d;
  border-radius: 10px;
  padding: 10px;
  margin-bottom: 10px;
  background: color-mix(in srgb, #102142 35%, #0b1328);
}

.scenario h3 {
  margin: 0 0 6px;
  font-size: 15px;
}

.helper {
  margin: 0 0 8px;
  color: #b8c6e6;
  font-size: 13px;
}

.field {
  display: grid;
  gap: 4px;
  min-width: 220px;
}

.field label {
  font-size: 12px;
  color: #c1cee9;
}

.required,
.optional {
  display: inline-block;
  margin-left: 6px;
  border-radius: 999px;
  font-size: 11px;
  padding: 2px 6px;
}

.required {
  background: #3f1f21;
  border: 1px solid #8a4249;
  color: #f9c4ca;
}

.optional {
  background: #21304f;
  border: 1px solid #48639a;
  color: #bfd0ff;
}

.divider {
  height: 1px;
  background: #2b3c65;
  margin: 10px 0;
}

h2 {
  margin: 0 0 12px;
  font-size: 18px;
}

p {
  margin: 6px 0;
}

.muted {
  color: var(--muted);
}

.tip {
  color: #9fb2da;
  font-size: 12px;
}

.explain {
  margin-top: 10px;
  color: #b7c5e6;
}

.row {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  margin-bottom: 8px;
}

input,
select,
button,
textarea {
  background: #0f1526;
  color: var(--text);
  border: 1px solid #2d3d62;
  border-radius: 8px;
  padding: 8px 10px;
}

textarea {
  width: 100%;
  resize: vertical;
}

button {
  cursor: pointer;
  border-color: #3a6cc0;
}

button:hover {
  border-color: var(--accent);
}

.out {
  margin: 0;
  min-height: 90px;
  max-height: 220px;
  overflow: auto;
  background: #090d1a;
  border: 1px solid #24314f;
  border-radius: 8px;
  padding: 10px;
  font-size: 12px;
}

.method-list {
  margin: 0;
  padding-left: 18px;
  line-height: 1.5;
}

.step-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 8px;
  margin: 8px 0 10px;
}

.step {
  padding: 8px 10px;
  border-radius: 8px;
  border: 1px solid #2d3d62;
  font-size: 12px;
}

.step-ok {
  border-color: color-mix(in srgb, var(--ok) 80%, white);
  background: color-mix(in srgb, var(--ok) 25%, black);
}

.step-run {
  border-color: color-mix(in srgb, var(--run) 80%, white);
  background: color-mix(in srgb, var(--run) 25%, black);
}

.step-wait {
  border-color: color-mix(in srgb, var(--wait) 85%, white);
  background: color-mix(in srgb, var(--wait) 20%, black);
}

.tile {
  display: grid;
  gap: 6px;
}

.btn-link {
  width: fit-content;
  text-decoration: none;
  color: var(--text);
  border: 1px solid #3a6cc0;
  border-radius: 8px;
  padding: 8px 10px;
  background: #0f1526;
}

const U = window.DemoUI;

function setUsersState(step, explain, payload) {
  U.markStep(step, "step-ok");
  U.setExplain("users-explain", explain);
  U.setOut("users-out", payload);
}

U.$("btn-register").addEventListener("click", async () => {
  try {
    const login = U.$("reg-login").value.trim();
    const password = U.$("reg-pass").value;
    if (!login || !password) {
      throw new Error("Для регистрации заполни логин и пароль.");
    }

    U.markStep("u-step-reg", "step-run");
    const user = await U.api("/api/users/register", "POST", {
      login,
      password,
      role: U.$("reg-role").value,
      hardwareToken: U.$("reg-token").value.trim() || null,
    });
    U.upsertUser(user);

    U.$("confirm-login").value = user.login;
    U.$("auth-login").value = user.login;
    U.$("auth-token").value = user.hardwareTokenSecret || "";
    U.$("role-login").value = user.login;
    U.$("ops-login").value = user.login;

    setUsersState(
      "u-step-reg",
      "register: пользователь создан, ключи и токен готовы. Теперь можно подтвердить аккаунт.",
      user
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-reg", "step-wait");
  }
});

U.$("btn-confirm").addEventListener("click", async () => {
  try {
    U.markStep("u-step-confirm", "step-run");
    const login = U.$("confirm-login").value.trim();
    if (!login) {
      throw new Error("Укажи логин для подтверждения аккаунта.");
    }
    const user = await U.api(`/api/users/${encodeURIComponent(login)}/confirm`, "POST");
    U.upsertUser(user);
    setUsersState(
      "u-step-confirm",
      "confirm: статус аккаунта становится активным, можно проходить 2FA.",
      user
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-confirm", "step-wait");
  }
});

U.$("btn-auth").addEventListener("click", async () => {
  try {
    U.markStep("u-step-auth", "step-run");
    const login = U.$("auth-login").value.trim();
    const password = U.$("auth-pass").value;
    const token = U.$("auth-token").value.trim();
    if (!login || !password || !token) {
      throw new Error("Для 2FA заполни логин, пароль и hardware token.");
    }
    const ok = await U.api("/api/users/auth", "POST", {
      login,
      password,
      hardwareToken: token,
    });
    setUsersState(
      "u-step-auth",
      "auth: сервер проверяет пароль и аппаратный токен (2FA).",
      { login, ok }
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-auth", "step-wait");
  }
});

U.$("btn-role").addEventListener("click", async () => {
  try {
    U.markStep("u-step-admin", "step-run");
    const login = U.$("role-login").value.trim();
    if (!login) {
      throw new Error("Укажи логин, для которого меняется роль.");
    }
    const user = await U.api(`/api/users/${encodeURIComponent(login)}/role`, "POST", {
      role: U.$("new-role").value,
    });
    U.upsertUser(user);
    setUsersState(
      "u-step-admin",
      "assign role: демонстрация RBAC. Роль пользователя обновлена.",
      user
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-admin", "step-wait");
  }
});

U.$("btn-rotate-token").addEventListener("click", async () => {
  try {
    U.markStep("u-step-admin", "step-run");
    const login = U.$("ops-login").value.trim();
    if (!login) {
      throw new Error("Укажи логин для ротации токена.");
    }
    const user = await U.api(`/api/users/${encodeURIComponent(login)}/token/rotate`, "POST");
    U.upsertUser(user);
    U.$("auth-token").value = user.hardwareTokenSecret || "";
    setUsersState(
      "u-step-admin",
      "rotate token: новый аппаратный токен выдан, для следующего auth используй его.",
      user
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-admin", "step-wait");
  }
});

U.$("btn-block").addEventListener("click", async () => {
  try {
    U.markStep("u-step-admin", "step-run");
    const login = U.$("ops-login").value.trim();
    if (!login) {
      throw new Error("Укажи логин для блокировки.");
    }
    const user = await U.api(`/api/users/${encodeURIComponent(login)}/block`, "POST", {
      reason: "demo-manual-block",
    });
    U.upsertUser(user);
    setUsersState(
      "u-step-admin",
      "block: пользователь принудительно заблокирован (админ сценарий).",
      user
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-admin", "step-wait");
  }
});

U.$("btn-recover").addEventListener("click", async () => {
  try {
    U.markStep("u-step-admin", "step-run");
    const login = U.$("ops-login").value.trim();
    if (!login) {
      throw new Error("Укажи логин для восстановления.");
    }
    const user = await U.api(`/api/users/${encodeURIComponent(login)}/recover`, "POST");
    U.upsertUser(user);
    setUsersState(
      "u-step-admin",
      "recover: восстановление после компрометации и ротация ключевого контекста.",
      user
    );
  } catch (e) {
    U.setOut("users-out", e.message);
    U.markStep("u-step-admin", "step-wait");
  }
});

U.setOut("users-out", "Начни со сценария A: регистрация -> подтверждение -> 2FA.");
